PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?beachLabel WHERE {
  VALUES ?label {
    "Omaha Beach" @en "Utah Beach" @en "Gold Beach" @en "Juno Beach" @en "Sword Beach" @en
  }
  ?beach rdfs:label ?label .
  ?beach wdt:P31 wd:Q193334 .
  FILTER(LANG(?label) = 'en')
}
